<script src="<?php echo JS; ?>/jquery.min.js"></script>
<script src="<?php echo JS; ?>/jquery.datetimepicker.min.js"></script>
<script>
	jQuery(document).ready(function () {
		jQuery('#input_1_12').datetimepicker({
			format: 'd/m/Y H:i', // Formato de fecha y hora
			minTime: '08:00', // Hora mínima por defecto
			maxTime: '20:30', // Hora máxima por defecto
			yearStart: <?php echo date('Y') ?>, // Año mínimo permitido
			minDate: 0, // Deshabilita los días anteriores al actual
			onShow: function () {
				const now = new Date(); // Fecha y hora actual
				const currentDay = now.toDateString();

				// Calcula la hora mínima dinámica para el día actual
				let minTimeToday = new Date(now.getTime() + 6 * 60 * 60 * 1000); // 6 horas desde ahora
				const formattedMinTimeToday = `${minTimeToday.getHours().toString().padStart(2, '0')}:${minTimeToday.getMinutes().toString().padStart(2, '0')}`;

				// Si el día actual está seleccionado, ajusta dinámicamente el rango de tiempo
				if (jQuery('#input_1_12').datetimepicker('getValue')?.toDateString() === currentDay) {
					jQuery('#input_1_12').datetimepicker('setOptions', {
						minTime: formattedMinTimeToday,
						maxTime: '20:30',
					});
				} else {
					// Restaura el rango de tiempo para otros días
					jQuery('#input_1_12').datetimepicker('setOptions', {
						minTime: '08:00',
						maxTime: '20:30',
					});
				}
			},
			onSelectDate: function (currentDate) {
				const now = new Date(); // Fecha y hora actual
				const currentDay = now.toDateString();
				const selectedDay = currentDate.toDateString();

				// Ajusta dinámicamente las horas solo si es el día actual
				if (selectedDay === currentDay) {
					let minTimeToday = new Date(now.getTime() + 6 * 60 * 60 * 1000); // 6 horas desde ahora
					const formattedMinTimeToday = `${minTimeToday.getHours().toString().padStart(2, '0')}:${minTimeToday.getMinutes().toString().padStart(2, '0')}`;

					jQuery('#input_1_12').datetimepicker('setOptions', {
						minTime: formattedMinTimeToday,
					});
				} else {
					// Restaura las horas para días futuros
					jQuery('#input_1_12').datetimepicker('setOptions', {
						minTime: '08:00',
						maxTime: '20:30',
					});
				}

				// Limpia el input si no se selecciona hora explícita
				jQuery('#input_1_12').val(''); // Elimina el valor temporal
			},
		});
	});
</script>